module multi_pipe_4bit
#(
    parameter SIZE = 4
)
(
    input clk,
    input rst_n,
    input [SIZE-1:0] mul_a,
    input [SIZE-1:0] mul_b,
    output reg [2*SIZE-1:0] mul_out
);

    localparam PIPE_DEPTH = 2;
    reg [SIZE-1:0] reg_a [PIPE_DEPTH-1:0];
    reg [SIZE-1:0] reg_b [PIPE_DEPTH-1:0];
    reg [2*SIZE-1:0] partial_products [PIPE_DEPTH-1:0];
    reg [2*SIZE-1:0] sum_products [PIPE_DEPTH-1:0];
    reg [2*SIZE-1:0] final_product;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_a[0] <= 0;
            reg_b[0] <= 0;
            partial_products[0] <= 0;
            sum_products[0] <= 0;
            final_product <= 0;
            mul_out <= 0;
        end else begin
            reg_a[0] <= mul_a;
            reg_b[0] <= mul_b;
            partial_products[0] <= reg_a[0] * reg_b[0];
            for (genvar i = 1; i < PIPE_DEPTH; i++) begin
                reg_a[i] <= reg_a[i-1];
                reg_b[i] <= reg_b[i-1];
                partial_products[i] <= partial_products[i-1];
                sum_products[i] <= sum_products[i-1] + partial_products[i-1];
            end
            final_product <= sum_products[PIPE_DEPTH-1];
            mul_out <= final_product;
        end
    end

endmodule
